// Pega dados do Webhook e do DeepSeek
const webhookData = $('Webhook').item.json.body.data;
const resposta = $input.item.json.choices?.[0]?.message?.content || "";

// --- CAÇADOR DE NÚMERO REAL (O Sniper) ---
const key = webhookData.key;

// 1. Lista de suspeitos onde o número pode estar
const candidatos = [
    key.remoteJidAlt,  // Geralmente o correto quando é o dono
    key.participant,   // Participante
    key.remoteJid      // Padrão (onde as vezes vem o LID chato)
];

// 2. Filtro: Pega o primeiro que termina com '@s.whatsapp.net' (Número Real)
// E ignora quem termina com '@lid' (Dispositivo)
let numeroReal = candidatos.find(num => num && num.includes('@s.whatsapp.net'));

// 3. Se não achou nenhum número real, usa o remoteJid mesmo como última opção
if (!numeroReal) {
    numeroReal = key.remoteJid;
}

// 4. Limpa o sufixo
const telefoneLimpo = numeroReal ? numeroReal.replace(/@.*/, '') : "Erro";

// --- RESTO DA LÓGICA ---
const precisa = resposta.toLowerCase().includes("<humano>sim</humano>");
const matchEtiqueta = resposta.match(/<tag>(.*?)<\/tag>/);
const etiqueta = matchEtiqueta ? matchEtiqueta[1] : null;

const limpa = resposta
    .replace(/<humano>.*?<\/humano>/gi, "")
    .replace(/<tag>.*?<\/tag>/gi, "")
    .trim();

return {
  resposta_limpa: limpa,
  precisa_humano: precisa,
  etiqueta_detectada: etiqueta,
  telefone_cliente: telefoneLimpo // O Sniper acertou aqui
};

// Entrada do DeepSeek
const resposta = $input.item.json.choices[0].message.content || "";

// Detecta se precisa de humano
const precisa = resposta.includes("<humano>sim</humano>");

// Remove as tags
const limpa = resposta.replace(/<humano>.*?<\/humano>/gi, "").trim();

// Retorna o objeto tratável no próximo node
return {
  resposta_limpa: limpa,
  precisa_humano: precisa
};

const dados = $input.item.json;

// 1. O RASTREADOR (Pega as mensagens onde estiverem)
let messages = [];
if (dados.messages && dados.messages.records) messages = dados.messages.records;
else if (dados.data) messages = dados.data;
else if (Array.isArray(dados)) messages = dados;

// 2. SEGURANÇA
if (!messages || messages.length === 0) {
    return { historico_conversa: "Sem histórico anterior." };
}

// 3. RECUPERAR MEMÓRIA (Pega as últimas 15)
// Estamos voltando para 15 para ele lembrar de tudo!
const ultimasMensagens = messages.slice(0, 15); 

// 4. FORMATAR E LIMPAR (O Segredo)
let lastSpeaker = ""; // Para detectar repetições
let historicoLimpo = [];

// Inverte para ficar na ordem cronológica (Antigo -> Novo)
const mensagensCronologicas = ultimasMensagens.reverse();

for (const msg of mensagensCronologicas) {
    const nome = msg.pushName || "Cliente";
    const quem = msg.key.fromMe ? "Atendente (IA)" : nome;

    const texto = 
        msg.message?.conversation || 
        msg.message?.extendedTextMessage?.text || 
        msg.message?.imageMessage?.caption || 
        (msg.message?.imageMessage ? "[FOTO do Cliente]" : null) ||
        (msg.message?.audioMessage ? "[ÁUDIO do Cliente]" : null) ||
        "";

    // FILTRO DE QUALIDADE:
    // 1. Ignora mensagens vazias
    // 2. Ignora se for exatamente igual à mensagem anterior (evita gagueira)
    // 3. Ignora mensagens de sistema/erro
    if (texto && texto !== "" && texto !== "undefined") {

        // Se a IA falou duas vezes seguidas a mesma coisa, ignora a segunda
        // (Isso corrige o erro que aconteceu antes)
        const mensagemAtual = `${quem}: ${texto}`;
        if (historicoLimpo.length > 0 && historicoLimpo[historicoLimpo.length - 1] === mensagemAtual) {
            continue; // Pula essa repetição
        }

        historicoLimpo.push(mensagemAtual);
    }
}

// Junta tudo
return { historico_conversa: historicoLimpo.join("\n") };
